import * as React from 'react';
import { createComponent } from '../create-component.js';
import Component from '../../components/loader/src/loader.component.js';
const tagName = 'made-loader';
Component.define(tagName);
/**
 * @summary The `made-loader` component is used to indicate loading states in your
 * application. It provides a visual cue to users that content is being loaded or
 * processed.
 * @documentation
 *
 * @slot - Use the default slot to add a label. Alternatively, you can use the `label` property to set a text label.
 *
 * @csspart base - The component's base wrapper.
 * @csspart spinner - The component's spinner element.
 * @csspart track - The component's track element.
 * @csspart indicator - The component's indicator element.
 * @csspart label - The component's label.
 *
 */
const reactWrapper = createComponent({
    tagName,
    elementClass: Component,
    react: React,
    events: {},
    displayName: 'MadeLoader'
});
export default reactWrapper;
